-- Helper: send JSON response
local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.header["X-Content-Type-Options"] = "nosniff"
    ngx.header["Cache-Control"] = "no-store, no-cache, must-revalidate"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

-- Helper: send error response
local function send_error(status, message, details)
    local resp = {
        success = false,
        error = message,
    }
    if details then
        resp.details = details
    end
    return send_json_response(status, resp)
end

-- Validate a single argument value
local function validate_argument(arg, index, command)
    if arg == nil then
        return false, string.format("Argument %d is nil", index)
    end

    local arg_str = tostring(arg)

    -- Check length
    if #arg_str > MAX_ARG_LENGTH then
        return false, string.format("Argument %d exceeds maximum length of %d bytes", index, MAX_ARG_LENGTH)
    end

    -- Check for null bytes (potential injection)
    if arg_str:find("\0") then
        return false, string.format("Argument %d contains null bytes", index)
    end

    return true, nil
end

-- Validate key name
local function validate_key(key)
    if not key or type(key) ~= "string" then
        return false, "Key must be a non-empty string"
    end

    if #key == 0 then
        return false, "Key must not be empty"
    end

    if #key > MAX_KEY_LENGTH then
        return false, string.format("Key exceeds maximum length of %d bytes", MAX_KEY_LENGTH)
    end

    -- Check for null bytes
    if key:find("\0") then
        return false, "Key contains null bytes"
    end

    -- Check allowed key prefixes if configured
    if #ALLOWED_KEY_PREFIXES > 0 then
        local prefix_ok = false
        for _, prefix in ipairs(ALLOWED_KEY_PREFIXES) do
            if key:sub(1, #prefix) == prefix then
                prefix_ok = true
                break
            end
        end
        if not prefix_ok then
            return false, string.format("Key '%s' does not match any allowed prefix", key)
        end
    end

    return true, nil
end

