-- Connect to Redis
local function connect_redis()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown error")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, auth_err = red:auth(REDIS_PASSWORD)
        if not res then
            red:close()
            return nil, "Redis authentication failed: " .. (auth_err or "unknown error")
        end
    end

    return red, nil
end

-- Return Redis connection to pool
local function keepalive_redis(red)
    if red then
        local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
        if not ok then
            ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
            red:close()
        end
    end
end

-- Simple IP-based rate limiting using shared dict
local function check_rate_limit()
    if not RATE_LIMIT_ENABLED then
        return true
    end

    local limit_dict = ngx.shared.redis_rate_limit
    if not limit_dict then
        ngx.log(ngx.WARN, "Rate limit shared dict 'redis_rate_limit' not configured, skipping rate limit")
        return true
    end

    local client_ip = ngx.var.remote_addr
    local key = "rl:" .. client_ip
    local count, err = limit_dict:incr(key, 1, 0, RATE_LIMIT_WINDOW)

    if not count then
        ngx.log(ngx.ERR, "Rate limit incr error: ", err)
        return true  -- fail open
    end

    if count > RATE_LIMIT_REQUESTS then
        return false
    end

    return true
end

-- Parse request body
local function parse_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        -- Check if body was written to a temp file
        local body_file = ngx.req.get_body_file()
        if body_file then
            local f = io.open(body_file, "r")
            if f then
                body = f:read("*a")
                f:close()
            end
        end
    end

    if not body or #body == 0 then
        return nil, "Request body is empty"
    end

    local ok, data = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON in request body"
    end

    return data, nil
end

-- Format Redis response for JSON output
local function format_redis_response(res, command)
    if type(res) == "userdata" then
        -- ngx.null
        return cjson.null
    end

    if type(res) == "table" then
        local formatted = {}
        local cmd = command:upper()

        -- HGETALL returns alternating field/value pairs - convert to object
        if cmd == "HGETALL" or cmd == "HMGET" then
            if cmd == "HGETALL" then
                local obj = {}
                for i = 1, #res, 2 do
                    local k = res[i]
                    local v = res[i + 1]
                    if type(v) == "userdata" then
                        v = cjson.null
                    end
                    obj[k] = v
                end
                return obj
            end
        end

        -- SCAN family returns {cursor, {results}}
        if cmd == "SCAN" or cmd == "HSCAN" or cmd == "SSCAN" or cmd == "ZSCAN" then
            if #res == 2 and type(res[2]) == "table" then
                local items = {}
                for _, v in ipairs(res[2]) do
                    if type(v) == "userdata" then
                        table.insert(items, cjson.null)
                    else
                        table.insert(items, v)
                    end
                end
                return {
                    cursor = res[1],
                    results = items,
                }
            end
        end

        -- Generic table formatting
        for i, v in ipairs(res) do
            if type(v) == "userdata" then
                formatted[i] = cjson.null
            elseif type(v) == "table" then
                formatted[i] = format_redis_response(v, command)
            else
                formatted[i] = v
            end
        end
        return formatted
    end

    return res
end

-- Execute a single Redis command
local function execute_command(red, command, args)
    local cmd = command:upper()

    -- Check if command is blocked
    if BLOCKED_COMMANDS[cmd] then
        return nil, string.format("Command '%s' is blocked for security reasons", cmd)
    end

    -- Check if command is allowed
    local cmd_spec = ALLOWED_COMMANDS[cmd]
    if not cmd_spec then
        return nil, string.format("Command '%s' is not in the allowlist", cmd)
    end

    -- Validate argument count
    local arg_count = args and #args or 0
    if arg_count < cmd_spec.min_args then
        return nil, string.format("Command '%s' requires at least %d argument(s), got %d",
            cmd, cmd_spec.min_args, arg_count)
    end
    if arg_count > cmd_spec.max_args then
        return nil, string.format("Command '%s' accepts at most %d argument(s), got %d",
            cmd, cmd_spec.max_args, arg_count)
    end

    -- Validate each argument
    for i, arg in ipairs(args) do
        local ok, err = validate_argument(arg, i, cmd)
        if not ok then
            return nil, err
        end
    end

    -- Validate keys
    local key_positions = get_key_positions(cmd, args)
    for pos, _ in pairs(key_positions) do
        if args[pos] then
            local ok, err = validate_key(tostring(args[pos]))
            if not ok then
                return nil, string.format("Key validation failed at argument %d: %s", pos, err)
            end
        end
    end

    -- Special validation for EVAL
    if cmd == "EVAL" then
        local ok, err = validate_eval_script(tostring(args[1]))
        if not ok then
            return nil, err
        end

        -- Validate numkeys is a valid number
        local numkeys = tonumber(args[2])
        if not numkeys or numkeys < 0 or numkeys ~= math.floor(numkeys) then
            return nil, "EVAL numkeys must be a non-negative integer"
        end

        -- Validate that the number of remaining args matches numkeys + numargs
        if numkeys > (arg_count - 2) then
            return nil, string.format("EVAL numkeys (%d) exceeds available arguments (%d)",
                numkeys, arg_count - 2)
        end

        -- Validate keys in EVAL
        for i = 3, 2 + numkeys do
            if args[i] then
                local key_ok, key_err = validate_key(tostring(args[i]))
                if not key_ok then
                    return nil, string.format("EVAL key validation failed at position %d: %s", i - 2, key_err)
                end
            end
        end
    end

    -- Build and execute the command
    local redis_func = red[cmd:lower()]
    if not redis_func then
        return nil, string.format("Redis client does not support command '%s'", cmd)
    end

    -- Convert all args to strings for Redis
    local string_args = {}
    for i, arg in ipairs(args) do
        string_args[i] = tostring(arg)
    end

    local res, err = redis_func(red, unpack(string_args))
    if not res then
        return nil, string.format("Redis command '%s' failed: %s", cmd, err or "unknown error")
    end

    return format_redis_response(res, cmd), nil
end

-- Main handler
local function handle_request()
    -- Only allow POST requests
    local method = ngx.req.get_method()
    if method ~= "POST" then
        return send_error(405, "Method not allowed. Use POST.")
    end

    -- Rate limiting
    if not check_rate_limit() then
        return send_error(429, "Rate limit exceeded. Please try again later.")
    end

    -- Parse request body
    local data, parse_err = parse_request_body()
    if not data then
        return send_error(400, "Failed to parse request body", parse_err)
    end

    -- Determine if single command or pipeline
    local is_pipeline = false
    local commands = {}

    if data.command then
        -- Single command mode
        if type(data.command) ~= "string" then
            return send_error(400, "Field 'command' must be a string")
        end
        local args = data.args or {}
        if type(args) ~= "table" then
            return send_error(400, "Field 'args' must be an array")
        end
        -- Ensure args is an array (not a hash)
        local clean_args = {}
        for i = 1, #args do
            clean_args[i] = args[i]
        end
        commands = { { command = data.command, args = clean_args } }
    elseif data.pipeline then
        -- Pipeline mode
        if type(data.pipeline) ~= "table" then
            return send_error(400, "Field 'pipeline' must be an array of commands")
        end
        if #data.pipeline == 0 then
            return send_error(400, "Pipeline must contain at least one command")
        end
        if #data.pipeline > 50 then
            return send_error(400, "Pipeline exceeds maximum of 50 commands")
        end
        is_pipeline = true
        for i, cmd_entry in ipairs(data.pipeline) do
            if type(cmd_entry) ~= "table" then
                return send_error(400, string.format("Pipeline entry %d must be an object", i))
            end
            if not cmd_entry.command or type(cmd_entry.command) ~= "string" then
                return send_error(400, string.format("Pipeline entry %d: 'command' must be a string", i))
            end
            local args = cmd_entry.args or {}
            if type(args) ~= "table" then
                return send_error(400, string.format("Pipeline entry %d: 'args' must be an array", i))
            end
            local clean_args = {}
            for j = 1, #args do
                clean_args[j] = args[j]
            end
            commands[i] = { command = cmd_entry.command, args = clean_args }
        end
    else
        return send_error(400, "Request must contain 'command' or 'pipeline' field")
    end

    -- Pre-validate all commands before connecting to Redis
    for i, cmd_entry in ipairs(commands) do
        local cmd = cmd_entry.command:upper()

        if BLOCKED_COMMANDS[cmd] then
            return send_error(403, string.format("Command '%s' is blocked for security reasons", cmd))
        end

        local cmd_spec = ALLOWED_COMMANDS[cmd]
        if not cmd_spec then
            return send_error(400, string.format("Command '%s' is not in the allowlist", cmd))
        end

        local arg_count = #cmd_entry.args
        if arg_count < cmd_spec.min_args or arg_count > cmd_spec.max_args then
            return send_error(400, string.format(
                "Command '%s' requires %d-%d argument(s), got %d",
                cmd, cmd_spec.min_args, cmd_spec.max_args, arg_count
            ))
        end
    end

    -- Connect to Redis
    local red, conn_err = connect_redis()
    if not red then
        ngx.log(ngx.ERR, "Redis connection error: ", conn_err)
        return send_error(503, "Redis service unavailable", conn_err)
    end

    local results = {}
    local has_error = false

    if is_pipeline and #commands > 1 then
        -- Use Redis pipeline for multiple commands
        red:init_pipeline(#commands)

        -- Queue all commands
        for i, cmd_entry in ipairs(commands) do
            local cmd = cmd_entry.command:upper()
            local redis_func = red[cmd:lower()]

            if not redis_func then
                keepalive_redis(red)
                return send_error(400, string.format("Redis client does not support command '%s'", cmd))
            end

            -- Validate keys and args
            local key_positions = get_key_positions(cmd, cmd_entry.args)
            for pos, _ in pairs(key_positions) do
                if cmd_entry.args[pos] then
                    local ok, err = validate_key(tostring(cmd_entry.args[pos]))
                    if not ok then
                        keepalive_redis(red)
                        return send_error(400, string.format(
                            "Pipeline entry %d: Key validation failed at argument %d: %s", i, pos, err))
                    end
                end
            end

            for j, arg in ipairs(cmd_entry.args) do
                local ok, err = validate_argument(arg, j, cmd)
                if not ok then
                    keepalive_redis(red)
                    return send_error(400, string.format("Pipeline entry %d: %s", i, err))
                end
            end

            -- Special EVAL validation
            if cmd == "EVAL" then
                local ok, err = validate_eval_script(tostring(cmd_entry.args[1]))
                if not ok then
                    keepalive_redis(red)
                    return send_error(400, string.format("Pipeline entry %d: %s", i, err))
                end
            end

            -- Convert args to strings
            local string_args = {}
            for j, arg in ipairs(cmd_entry.args) do
                string_args[j] = tostring(arg)
            end

            redis_func(red, unpack(string_args))
        end

        -- Commit pipeline
        local pipeline_results, pipeline_err = red:commit_pipeline()
        if not pipeline_results then
            keepalive_redis(red)
            ngx.log(ngx.ERR, "Redis pipeline error: ", pipeline_err)
            return send_error(500, "Redis pipeline execution failed", pipeline_err)
        end

        for i, res in ipairs(pipeline_results) do
            local cmd = commands[i] and commands[i].command or "UNKNOWN"
            if type(res) == "table" and res[1] == false then
                results[i] = {
                    success = false,
                    error = res[2] or "Unknown error",
                    command = cmd,
                }
                has_error = true
            else
                results[i] = {
                    success = true,
                    result = format_redis_response(res, cmd),
                    command = cmd,
                }
            end
        end
    else
        -- Single command execution
        for i, cmd_entry in ipairs(commands) do
            local res, err = execute_command(red, cmd_entry.command, cmd_entry.args)
            if err then
                results[i] = {
                    success = false,
                    error = err,
                    command = cmd_entry.command,
                }
                has_error = true
            else
                results[i] = {
                    success = true,
                    result = res,
                    command = cmd_entry.command,
                }
            end
        end
    end

    -- Return connection to pool
    keepalive_redis(red)

    -- Build response
    local response
    if is_pipeline then
        response = {
            success = not has_error,
            pipeline = true,
            results = results,
            count = #results,
        }
    else
        -- Single command - flatten response
        local single = results[1]
        response = {
            success = single.success,
            command = single.command,
        }
        if single.success then
            response.result = single.result
        else
            response.error = single.error
        end
    end

    local status = 200
    if has_error and not is_pipeline then
        -- For single commands, determine appropriate status
        local err_msg = results[1].error or ""
        if err_msg:find("not in the allowlist") or err_msg:find("blocked") then
            status = 403
        elseif err_msg:find("requires at least") or err_msg:find("accepts at most")
            or err_msg:find("validation failed") then
            status = 400
        else
            status = 500
        end
    end

    return send_json_response(status, response)
end

-- Execute the handler
handle_request()